const feeds = String($env.DW_RSS_FEEDS || '').split(',').map(s => s.trim()).filter(Boolean);
if (!feeds.length) return [];
return feeds.map(url => ({ json: { url } }));

return items.map(({ json }) => {
  const url = json.link || json.guid || json.url;
  const text = String(json.content || json.contentSnippet || json.description || json.text || json.title || '').trim();
  if (!url || !json.title) return null;
  const locale = /[а-яё]/i.test(String(json.title) + ' ' + text) ? 'ru' : 'en';
  return { json: {
    externalId: String(json.guid || url),
    sourcePlatform: 'rss',
    sourceName: json.feedTitle || json.creator || 'RSS / News',
    sourceUrl: String(url),
    canonicalUrl: String(url).split('#')[0],
    author: json.creator || json.author || null,
    locale,
    title: String(json.title).slice(0, 500),
    rawContent: text || String(json.title),
    imageUrl: json.imageUrl || json.enclosure?.url || null,
    publishedAt: json.isoDate || json.pubDate || null,
    category: 'ai'
  }};
}).filter(Boolean);

const queries = String($env.DW_HN_QUERIES || 'AI agents,robotics,automation,OpenAI,Claude,Gemini').split(',').map(s => s.trim()).filter(Boolean);
const after = Math.floor((Date.now() - 48 * 60 * 60 * 1000) / 1000);
return queries.map(query => ({ json: { query, after, hitsPerPage: 25 } }));

const hits = $json.hits || [];
return hits.filter(hit => hit && hit.title && (hit.url || hit.objectID)).slice(0, 20).map(hit => {
  const discussion = 'https://news.ycombinator.com/item?id=' + hit.objectID;
  const sourceUrl = hit.url || discussion;
  const raw = [
    hit.title,
    hit.story_text || '',
    'HN points: ' + (hit.points ?? 0),
    'HN comments: ' + (hit.num_comments ?? 0),
    'Discussion: ' + discussion
  ].filter(Boolean).join('
');
  return { json: {
    externalId: 'hn:' + hit.objectID,
    sourcePlatform: 'manual',
    sourceName: 'Hacker News',
    sourceUrl,
    canonicalUrl: sourceUrl.split('#')[0],
    author: hit.author || null,
    locale: 'en',
    title: String(hit.title).slice(0, 500),
    rawContent: raw,
    imageUrl: null,
    publishedAt: hit.created_at || null,
    category: 'ai'
  }};
});

const list = $json.items || [];
return list.map(item => {
  const videoId = item.id?.videoId;
  if (!videoId) return null;
  const s = item.snippet || {};
  return { json: {
    videoId,
    title: s.title,
    description: s.description || '',
    channelTitle: s.channelTitle || 'YouTube',
    publishedAt: s.publishedAt || null,
    imageUrl: s.thumbnails?.high?.url || s.thumbnails?.medium?.url || null,
    url: 'https://www.youtube.com/watch?v=' + videoId
  }};
}).filter(Boolean);

const crypto = require('node:crypto');
const secret = $env.N8N_INTEGRATION_SECRET;
if (!secret) throw new Error('N8N_INTEGRATION_SECRET is not configured');
function cleanUrl(value) { return String(value || '').split('#')[0]; }
return items.map(({ json }) => {
  if (!json.sourceUrl || !json.title || !json.rawContent) return null;
  const canonicalUrl = cleanUrl(json.canonicalUrl || json.sourceUrl);
  const compact = String(json.rawContent).replace(/s+/g, ' ').trim();
  const payload = {
    externalId: String(json.externalId || canonicalUrl).slice(0, 500),
    sourcePlatform: ['rss','reddit','x','threads','manual'].includes(json.sourcePlatform) ? json.sourcePlatform : 'manual',
    sourceName: String(json.sourceName || 'Den Workspace Source').slice(0, 180),
    sourceUrl: String(json.sourceUrl),
    canonicalUrl,
    author: json.author ? String(json.author).slice(0, 180) : null,
    locale: json.locale === 'ru' ? 'ru' : 'en',
    title: String(json.title).slice(0, 500),
    rawContent: String(json.rawContent),
    imageUrl: json.imageUrl || null,
    publishedAt: json.publishedAt || null,
    fingerprint: crypto.createHash('sha256').update(canonicalUrl + '|' + compact.slice(0, 4000)).digest('hex'),
    category: String(json.category || 'ai').slice(0, 80)
  };
  const rawBody = JSON.stringify(payload);
  const signature = 'sha256=' + crypto.createHmac('sha256', secret).update(rawBody).digest('hex');
  return { json: { payload, rawBody, signature } };
}).filter(Boolean);

if ($json.duplicate === true) return [];
const source = $('Normalize + Sign Ingest').item.json.payload;
if (!$json.article?.id || !$json.article?.version) throw new Error('Ingest response has no article');
return [{ json: { article: $json.article, source } }];

