const crypto = require('node:crypto');
const secret = $env.N8N_INTEGRATION_SECRET;
const prepared = $('Only New Articles').item.json;
const content = $json.choices?.[0]?.message?.content;
if (!content) throw new Error('AI response does not contain JSON content');
let editorial;
try { editorial = typeof content === 'string' ? JSON.parse(content) : content; } catch (error) { throw new Error('AI returned invalid JSON: ' + error.message); }
const payload = {
  articleId: prepared.article.id,
  expectedVersion: prepared.article.version,
  locale: prepared.source.locale,
  title: String(editorial.title || '').slice(0, 220),
  summary: String(editorial.summary || '').slice(0, 800),
  body: String(editorial.body || ''),
  seoTitle: editorial.seoTitle ? String(editorial.seoTitle).slice(0, 220) : null,
  seoDescription: editorial.seoDescription ? String(editorial.seoDescription).slice(0, 500) : null,
  telegramText: editorial.telegramText ? String(editorial.telegramText).slice(0, 4096) : null,
  category: String(editorial.category || prepared.source.category || 'ai').slice(0, 80),
  tags: Array.isArray(editorial.tags) ? editorial.tags.slice(0, 12).map(String) : [],
  factWarnings: Array.isArray(editorial.factWarnings) ? editorial.factWarnings.slice(0, 20).map(String) : []
};
if (!payload.title || !payload.summary || !payload.body) throw new Error('AI editorial result is incomplete');
const rawBody = JSON.stringify(payload);
const signature = 'sha256=' + crypto.createHmac('sha256', secret).update(rawBody).digest('hex');
return [{ json: { payload, rawBody, signature } }];

const crypto = require('node:crypto');
const article = $('Save Editorial Result').item.json.article;
const action = 'approve';
const payload = { articleId: article.id, articleVersion: article.version, action };
const rawBody = JSON.stringify(payload);
const signature = 'sha256=' + crypto.createHmac('sha256', $env.N8N_INTEGRATION_SECRET).update(rawBody).digest('hex');
return [{ json: { rawBody, signature, action } }];

const crypto = require('node:crypto');
const article = $('Save Editorial Result').item.json.article;
const action = 'reject';
const payload = { articleId: article.id, articleVersion: article.version, action };
const rawBody = JSON.stringify(payload);
const signature = 'sha256=' + crypto.createHmac('sha256', $env.N8N_INTEGRATION_SECRET).update(rawBody).digest('hex');
return [{ json: { rawBody, signature, action } }];

const crypto = require('node:crypto');
const article = $('Save Editorial Result').item.json.article;
const action = 'regenerate';
const payload = { articleId: article.id, articleVersion: article.version, action };
const rawBody = JSON.stringify(payload);
const signature = 'sha256=' + crypto.createHmac('sha256', $env.N8N_INTEGRATION_SECRET).update(rawBody).digest('hex');
return [{ json: { rawBody, signature, action } }];

const editorial = $('Parse + Sign Editorial').item.json.payload;
const source = $('Only New Articles').item.json.source;
const approve = $('Create Approve Token').item.json.token;
const reject = $('Create Reject Token').item.json.token;
const regenerate = $('Create Regenerate Token').item.json.token;
const escape = (v) => String(v || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
const adminUrl = ($env.DENS_SITE_URL || '').replace(//$/, '') + '/admin/articles/' + editorial.articleId;
const text = [
  '<b>' + escape(editorial.title) + '</b>',
  escape(editorial.summary),
  '',
  'Source: ' + escape(source.canonicalUrl),
  'Admin: ' + escape(adminUrl)
].join('

');
const payload = {
  chat_id: $env.TELEGRAM_APPROVAL_CHAT_ID,
  message_thread_id: editorial.locale === 'ru' ? ($env.TELEGRAM_APPROVAL_TOPIC_RU || undefined) : ($env.TELEGRAM_APPROVAL_TOPIC_EN || undefined),
  text,
  parse_mode: 'HTML',
  disable_web_page_preview: false,
  reply_markup: {
    inline_keyboard: [[
      { text: 'Approve', callback_data: 'approve:' + approve },
      { text: 'Reject', callback_data: 'reject:' + reject },
      { text: 'Regenerate', callback_data: 'regenerate:' + regenerate }
    ], [
      { text: 'Edit in Admin', url: adminUrl }
    ]]
  }
};
Object.keys(payload).forEach(key => payload[key] === undefined && delete payload[key]);
return [{ json: { payload } }];

const crypto = require('node:crypto');
const callback = $json.callback_query;
if (!callback?.data || !callback?.from?.id) throw new Error('Invalid Telegram callback');
const token = String(callback.data).split(':').slice(1).join(':');
const payload = { token, telegramUserId: String(callback.from.id) };
const rawBody = JSON.stringify(payload);
const signature = 'sha256=' + crypto.createHmac('sha256', $env.N8N_INTEGRATION_SECRET).update(rawBody).digest('hex');
return [{ json: { rawBody, signature, callbackQueryId: callback.id } }];

const crypto = require('node:crypto');
const rawBody = JSON.stringify({ jobId: $json.id, articleId: $json.article_id });
const signature = 'sha256=' + crypto.createHmac('sha256', $env.N8N_INTEGRATION_SECRET).update(rawBody).digest('hex');
return [{ json: { job: $json, rawBody, signature } }];

const crypto = require('node:crypto');
const job = $('Sign Site Revalidate').item.json.job;
const payload = { jobId: job.id, status: 'published', externalUrl: ($env.DENS_SITE_URL || '').replace(//$/, '') + '/news-feed' };
const rawBody = JSON.stringify(payload);
const signature = 'sha256=' + crypto.createHmac('sha256', $env.N8N_INTEGRATION_SECRET).update(rawBody).digest('hex');
return [{ json: { rawBody, signature } }];

const localizations = $json.articles?.article_localizations || [];
const preferred = localizations.find(item => item.locale === 'ru') || localizations[0];
if (!preferred) throw new Error('Publication has no localization');
const link = ($env.DENS_SITE_URL || '').replace(//$/, '') + '/news-feed/' + preferred.slug;
const escape = (v) => String(v || '').replace(/[<>&]/g, '');
return [{ json: { job: $json, text: preferred.telegram_text || ('<b>' + escape(preferred.title) + '</b>

' + escape(preferred.summary) + '

' + link) } }];

const crypto = require('node:crypto');
const job = $('Prepare Telegram Publication').item.json.job;
const payload = { jobId: job.id, status: 'published', externalId: String($json.message_id || $json.result?.message_id || '') || null };
const rawBody = JSON.stringify(payload);
const signature = 'sha256=' + crypto.createHmac('sha256', $env.N8N_INTEGRATION_SECRET).update(rawBody).digest('hex');
return [{ json: { rawBody, signature } }];
